ValidationRule.errorConditionFormula:
AND( OR( ISPICKVAL(PRIORVALUE(StageName), 'Elaboração de Contrato'), ISPICKVAL(PRIORVALUE(StageName), 'Contrato assinado')
), NOT(ISPICKVAL(StageName, 'Contrato assinado')),
NOT(ISPICKVAL(StageName, 'Contrato Enviado')), NOT(ISPICKVAL(StageName, 'Perdido')), NOT($Profile.Name = "Administrador do sistema"), NOT($UserRole.Name = "Formalização"), NOT($UserRole.Name = "Executivo de Formalização") )
